import Foundation
import SwiftUI

enum AppLanguage: String, CaseIterable, Identifiable {
    case ru = "ru"
    case en = "en"
    case vi = "vi"
    case ko = "ko"
    case es = "es"
    case zh = "zh"
    case fr = "fr"
    
    var id: String { self.rawValue }
    
    var displayName: String {
        switch self {
        case .ru: return "Русский"
        case .en: return "English"
        case .vi: return "Tiếng Việt"
        case .ko: return "한국어"
        case .es: return "Español"
        case .zh: return "中文"
        case .fr: return "Français"
        }
    }
}

class LocalizationManager: ObservableObject {
    static let shared = LocalizationManager()
    
    @Published var currentLanguage: AppLanguage {
        didSet {
            UserDefaults.standard.set(currentLanguage.rawValue, forKey: "selected_language")
        }
    }
    
    private init() {
        if let saved = UserDefaults.standard.string(forKey: "selected_language"),
           let language = AppLanguage(rawValue: saved) {
            self.currentLanguage = language
        } else {
            // Первый запуск — определяем системный язык
            self.currentLanguage = Self.detectSystemLanguage()
        }
    }
    
    /// Определяет системный язык и подбирает ближайший из поддерживаемых (или EN)
    private static func detectSystemLanguage() -> AppLanguage {
        let systemLang = Locale.preferredLanguages.first?.prefix(2).lowercased() ?? ""
        
        switch systemLang {
        case "ru": return .ru
        case "vi": return .vi
        case "ko": return .ko
        case "es": return .es
        case "zh": return .zh
        case "fr": return .fr
        default: return .en // По стандарту предлагаем английский
        }
    }
    
