        "filter_done": [.ru: "Готово", .en: "Done", .vi: "Xong", .ko: "완료", .es: "Hecho", .zh: "完成", .fr: "Terminé"],
        
        // POI Names (Original Brand Names)
        "poi_beach_city_name": [.ru: "Nha Trang City Beach", .en: "Nha Trang City Beach", .vi: "Bãi biển Nha Trang", .ko: "Nha Trang City Beach", .es: "Playa de Nha Trang", .zh: "芽庄市海滩", .fr: "Plage de Nha Trang"],
        "poi_beach_city_desc": [.ru: "Главный пляж города протяжённостью 7 км. Идеальное место для утренних прогулок и купания.", .en: "The city's main 7km beach. Perfect for morning walks and swimming.", .vi: "Bãi biển chính của thành phố dài 7km. Nơi lý tưởng để đi dạo và tắm biển.", .ko: "부드러운 모래와 깨끗한 물이 있는 7km 길이의 메인 시티 비치입니다.", .es: "La playa principal de la ciudad que abarca 7 km con arena fina y agua cristalina.", .zh: "跨越 7 公里的主要城市海滩，拥有细腻的沙滩和清澈的海水。", .fr: "La plage principale de la ville s'étendant sur 7 km avec du sable fin et une eau claire."],
        
        "poi_beach_bai_dai_name": [.ru: "Bãi Dài Beach", .en: "Bãi Dài Beach", .vi: "Bãi Dài", .ko: "Bai Dai Beach", .es: "Playa Bai Dai", .zh: "白黛海滩", .fr: "Plage de Bai Dai"],
        "poi_beach_bai_dai_desc": [.ru: "Уединённый пляж с лазурной водой в 20 км от центра. Славится свежими морепродуктами.", .en: "A secluded beach with azure water 20km from the center. Famous for fresh seafood.", .vi: "Bãi biển biệt lập với làn nước xanh ngắt cách trung tâm 20km. Nổi tiếng với hải sản tươi sống.", .ko: "남쪽으로 20km 떨어진 조용한 해변. 덜 붐비고 수정처럼 맑은 물.", .es: "Una playa tranquila a 20 km al sur. Menos concurrida, agua cristalina.", .zh: "位于南部 20 公里处的安静海滩。人少，水质清澈。", .fr: "Une plage calme à 20 km au sud. Moins de monde, eau cristalline."],
        
        "poi_beach_doc_let_name": [.ru: "Dốc Lết Beach", .en: "Dốc Lết Beach", .vi: "Bãi Dốc Lết", .ko: "Doc Let Beach", .es: "Playa Doc Let", .zh: "佐乐海滩", .fr: "Plage de Doc Let"],
        "poi_beach_doc_let_desc": [.ru: "Белоснежный песок и мелководье. Одно из самых красивых мест в провинции Кханьхоа.", .en: "White powdery sand and shallow waters. One of the most beautiful spots in Khanh Hoa province.", .vi: "Cát trắng mịn và nước nông. Một trong những điểm đẹp nhất tỉnh Khánh Hòa.", .ko: "나트랑에서 북쪽으로 50km 떨어진 그림 같은 백사장 해변.", .es: "Una playa pintoresca de arena blanca a 50 km al norte de Nha Trang.", .zh: "芽庄以北 50 公里处风景如画的白沙滩。", .fr: "Une plage pittoresque de sable blanc à 50 km au nord de Nha Trang."],
        
        "poi_rest_lanterns_name": [.ru: "Lanterns Vietnamese", .en: "Lanterns Vietnamese", .vi: "Lanterns Vietnamese", .ko: "Lanterns Vietnamese", .es: "Lanterns Vietnamese", .zh: "Lanterns Vietnamese", .fr: "Lanterns Vietnamese"],
        "poi_rest_lanterns_desc": [.ru: "Аутентичная кухня и мастер-классы. Ресторан активно поддерживает местные благотворительные проекты.", .en: "Authentic cuisine and cooking classes. The restaurant actively supports local charity projects.", .vi: "Ẩm thực bản địa và các lớp học nấu ăn. Nhà hàng tích cực hỗ trợ các dự án từ thiện địa phương.", .ko: "도시에서 가장 좋은 베트남 레스토랑 중 하나입니다.", .es: "Uno de los mejores restaurantes vietnamitas de la ciudad.", .zh: "市内最好的越南餐厅之一。", .fr: "L'un des meilleurs restaurants vietnamiens de la ville."],
        
        "poi_rest_louisiane_name": [.ru: "Louisiane Brewhouse", .en: "Louisiane Brewhouse", .vi: "Louisiane Brewhouse", .ko: "Louisiane Brewhouse", .es: "Louisiane Brewhouse", .zh: "Louisiane Brewhouse", .fr: "Louisiane Brewhouse"],
        "poi_rest_louisiane_desc": [.ru: "Единственная пивоварня на берегу. Собственный бассейн и живая музыка по вечерам.", .en: "The only beachfront brewery. Private pool and live music in the evenings.", .vi: "Xưởng bia duy nhất bên bờ biển. Có hồ bơi riêng và nhạc sống vào buổi tối.", .ko: "해변가 레스토랑 겸 양조장. 해산물과 수제 맥주.", .es: "Restaurante y cervecería frente al mar. Mariscos y cerveza artesanal.", .zh: "海滨餐厅和啤酒厂。海鲜和精酿啤酒。", .fr: "Restaurant et brasserie en bord de mer. Fruits de mer et bière artisanale."],
        
        "poi_rest_mix_name": [.ru: "Mix Restaurant", .en: "Mix Restaurant", .vi: "Mix Restaurant", .ko: "Mix Restaurant", .es: "Mix Restaurant", .zh: "Mix Restaurant", .fr: "Mix Restaurant"],
        "poi_rest_mix_desc": [.ru: "Огромные сеты греческой кухни. Очень популярное место с дружелюбной атмосферой.", .en: "Giant Greek platters. A very popular spot with a friendly atmosphere.", .vi: "Các phần ăn Hy Lạp khổng lồ. Một địa điểm rất nổi tiếng với không khí thân thiện.", .ko: "베이 뷰가 있는 그리스 요리.", .es: "Cocina griega con vistas a la bahía.", .zh: "可以欣赏海湾美景的希腊美食。", .fr: "Cuisine grecque avec vue sur la baie."],
        
        "poi_temple_ponagar_name": [.ru: "Tháp Bà Ponagar", .en: "Po Nagar Towers", .vi: "Tháp Bà Ponagar", .ko: "Po Nagar Towers", .es: "Torres Po Nagar", .zh: "婆那加占婆塔", .fr: "Tours Po Nagar"],
        "poi_temple_ponagar_desc": [.ru: "Величественные храмы цивилизации Чам, построенные более тысячи лет назад.", .en: "Majestic Cham temples built over a thousand years ago.", .vi: "Những ngôi đền Chăm hùng vĩ được xây dựng từ hơn một ngàn năm trước.", .ko: "7-12세기 참 문명의 고대 사원 복합체.", .es: "Antiguo complejo de templos de la civilización Cham de los siglos VII-XII.", .zh: "7-12世纪占婆文明的古老寺庙群。", .fr: "Ancien complexe de temples de la civilisation Cham du 7-12ème siècle."],
        
        "poi_temple_long_son_name": [.ru: "Chùa Long Sơn", .en: "Long Son Pagoda", .vi: "Chùa Long Sơn", .ko: "Long Son Pagoda", .es: "Pagoda Long Son", .zh: "龙山寺", .fr: "Pagode de Long Son"],
        "poi_temple_long_son_desc": [.ru: "Главная буддийская святыня города с огромным Белым Буддой, видимым издалека.", .en: "The city's main Buddhist shrine with a giant White Buddha visible from afar.", .vi: "Ngôi chùa biểu tượng của thành phố với bức tượng Phật Trắng khổng lồ nhìn từ xa.", .ko: "언덕 꼭대기에 큰 불상이 있는 19세기 불교 사원.", .es: "Templo budista del siglo XIX con una gran estatua de Buda en la cima de una colina.", .zh: "19 世纪的佛教寺庙，山顶有一尊大佛像。", .fr: "Temple bouddhiste du XIXe siècle doté d'une grande statue de Bouddha au sommet d'une colline."],
        
        "poi_ent_vinpearl_name": [.ru: "VinWonders Nha Trang", .en: "VinWonders Nha Trang", .vi: "VinWonders Nha Trang", .ko: "VinWonders Nha Trang", .es: "VinWonders Nha Trang", .zh: "珍珠岛乐园", .fr: "VinWonders Nha Trang"],
        "poi_ent_vinpearl_desc": [.ru: "Остров приключений. Канатная дорога над морем и развлечения для всей семьи.", .en: "Adventure island. Over-sea cable car and entertainment for the whole family.", .vi: "Đảo phiêu lưu. Cáp treo vượt biển và các hoạt động giải trí cho cả gia đình.", .ko: "혼트레 섬의 테마파크. 케이블카, 워터파크.", .es: "Parque temático en la isla Hon Tre. Teleférico, parque acuático.", .zh: "竹岛上的主题公园。缆车、水上乐园。", .fr: "Parc à thème sur l'île de Hon Tre. Téléphérique, parc aquatique."],
        "poi_rest_grill_garden_name": [.ru: "Grill Garden (BBQ Buffet)", .en: "Grill Garden (BBQ Buffet)", .vi: "Grill Garden (BBQ Buffet)", .ko: "Grill Garden (BBQ Buffet)", .es: "Grill Garden (BBQ Buffet)", .zh: "Grill Garden (BBQ Buffet)", .fr: "Grill Garden (BBQ Buffet)"],
        "poi_rest_grill_garden_desc": [.ru: "Популярный ресторан со шведским столом и грилем. Большой выбор морепродуктов и мяса в самом центре города.", .en: "Popular BBQ buffet restaurant in the city center. Large selection of seafood and grilled meats.", .vi: "Nhà hàng buffet nướng nổi tiếng ở trung tâm thành phố. Thực đơn đa dạng với hải sản và các loại thịt nướng.", .ko: "시내 중심가에 위치한 인기 있는 BBQ 뷔페 레스토랑. 다양한 해산물과 구운 육류를 즐길 수 있습니다.", .es: "Popular restaurante de buffet de barbacoa en el centro de la ciudad. Gran selección de mariscos y carnes a la parrilla.", .zh: "市中心受欢迎的烧烤自助餐厅。提供丰富的海鲜和烤肉选择。", .fr: "Populaire restaurant buffet BBQ au centre-ville. Large sélection de fruits de mer et de viandes grillées."],
